npm install —save-dev stylelint stylelint-config-standard stylelint-order stylelint-config-recess-order postcss-htmlnpm install —save-dev stylelint-config-standard-scss
在项目根目录下创建 `.stylelintrc.mjs` 文件，并添加以下内容：``js/** @type {import('stylelint').Config} */export default {  extends: [    // 基础配置 (包含了 CSS Modules 和 现代 CSS 特性检查)    "stylelint-config-standard",    // 如果你使用 SCSS，取消下面这行的注释，并注释掉上面那行    // "stylelint-config-standard-scss",    // 属性自动排序    "stylelint-config-recess-order",  ],  // 针对不同文件类型的特定覆盖  overrides: [    {      files: ["**/*.{html,vue}"],      customSyntax: "postcss-html",    },    {      files: ["**/*.{jsx,tsx}"],      customSyntax: "postcss-styled-syntax", // 如果使用 CSS-in-JS    }  ],  rules: {    // 1. 强制使用现代颜色函数 (如 oklch, lab, 或逗号分隔的 rgb 新语法)    "color-function-notation": "modern",    // 2. 透明度使用百分比写法 (opacity: 50% 而不是 0.5)    "alpha-value-notation": "percentage",    // 3. 限制选择器特异性 (防止嵌套过深，配合原生 CSS Nesting)    "selector-max-specificity": "0,4,0",    "max-nesting-depth": 3,    // 4. 强制使用伪元素双冒号 (::before 而不是 :before)    "selector-pseudo-element-colon-notation": "double",    // 5. 禁止未知的伪类 (兼容未来的 CSS 伪类)    "selector-pseudo-class-no-unknown": [      true,      {        ignorePseudoClasses: ["global", "deep", "slotted"],      },    ],    /* ------------------------------------------------       逻辑属性 (Logical Properties)       强制使用 margin-inline-start 而非 margin-left       ------------------------------------------------ */       // 6. 禁止空的代码块    "block-no-empty": true,    // 7. 自定义类名模式 (BEM 或 Kebab-case)    "selector-class-pattern": [      "^[a-z]([a-z0-9-]+)?(__([a-z0-9]+))?(--([a-z0-9]+))?$",      {        message: "Expected class selector to be BEM pattern",      },    ],    /* ------------------------------------------------       与 Prettier 的兼容    ------------------------------------------------ */    // "comment-empty-line-before": null,},  // 忽略文件  ignoreFiles: ["dist/**/*", "node_modules/**/*", "**/*.min.css"],};
