//求栈长int Length_LinkedStack(LinkedStack top)                                       &#123;	int count = 0;	while(top-&gt;next!=NULL) 	&#123;		++count;		top=top-&gt;next;	&#125;	return count;&#125;
完整代码实现#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;// 定义链式栈的节点结构体typedef struct LinkedStackNode &#123;	    int data;                       // 存储栈元素    struct LinkedStackNode * next;  // 指向下一节点的指针&#125; LinkedStackNode, * LinkedStack;   // 类型别名：LinkedStackNode表示节点，LinkedStack表示节点指针LinkedStack top; // 声明一个栈顶指针（本质是LinkedStackNode*类型）//初始化LinkedStack Init_LinkedStack()                                       &#123;		LinkedStack top=(LinkedStackNode * )malloc (sizeof( LinkedStackNode));	if(top!=NULL)//申请空间成功	top-&gt;next=NULL;//设置栈顶指针为空	return top;&#125;//判栈空int LinkedStack_Empty(LinkedStack top)                            &#123;		if(top-&gt;next==NULL)//检查栈顶指针的值 	&#123;		return 1;//栈S为空，函数返回1	&#125;		else	&#123;		return 0;	&#125;&#125;//入栈int Push_LinkedStack(LinkedStack top,elemtype x)                     	//插入数据元素x为新的栈顶元素&#123;		LinkedStackNode * node;	node=(LinkedStackNode * )malloc(sizeof(LinkedStackNode));	if(node==NULL)	&#123;		return 0;//申请结点空间失败,插入失败，函数返回0	&#125;	else	&#123;		node-&gt;data=x;//设置新结点的数据域		node-&gt;next=top-&gt;next;//设置新结点的指针城		top-&gt;next=node;//设置头结点指针城指向新的栈顶元素		return 1;//插入成功，函数返回1	&#125;&#125;//求栈长int Length_LinkedStack(LinkedStack top)                                       &#123;	int count = 0;	while(top-&gt;next!=NULL) 	&#123;		++count;		top=top-&gt;next;	&#125;	return count;&#125;//出栈int Pop_LinkedStack(LinkedStack top, elemtype *x)                    &#123;	LinkedStackNode * node;	if(top-&gt;next==NULL)	&#123;		return 0;	&#125;	else	&#123;		node=top-&gt;next;//将原栈顶数据元素弹出并赋给node		*x=node-&gt;data;//将原栈顶数据元素的数据赋值给x		top-&gt;next=node-&gt;next;//top指向链栈中的下一个数据元素		free (node);//释放原栈顶数据元素所占的空间		return 1;	&#125;&#125;  //取栈顶元素int GetTop_LinkedStack(LinkedStack top)                &#123; 	if(top-&gt;next)      &#123;            return top-&gt;next-&gt;data;      &#125;      return -1;&#125;//主函数void main()&#123;	int i,t,x,a[20];	LinkedStack top=Init_LinkedStack();//初始化栈	x=LinkedStack_Empty(top);//判栈空结果赋值给X	if(x=0)	&#123;		printf(&quot;栈为空\n&quot;);	&#125;	printf(&quot;请依次输入5个数,开始入栈：\n&quot;);	for(i=0;i&lt;5;i++) 	&#123;		scanf(&quot;%d&quot;,&amp;a[i]);		Push_LinkedStack(top,a[i]);		x=GetTop_LinkedStack(top);		if(x!=-1)		&#123;			printf(&quot;当前栈顶元素为%d\n&quot;,x);		&#125;	&#125;	printf(&quot;入栈结束\n&quot;);	printf(&quot;栈长为%d\n&quot;,Length_LinkedStack(top));	printf(&quot;开始出栈:\n&quot;);	for (i=0;i&lt;5;i++)	&#123;		Pop_LinkedStack(top,&amp;t);        printf(&quot;%d&quot;,t);	&#125;	printf(&quot;\n&quot;);	printf(&quot;出栈后栈长为%d\n&quot;,Length_LinkedStack(top));&#125;
